import React, { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import {
  Drawer,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Toolbar,
  Typography,
  Box,
  Divider,
  Collapse,
  Avatar,
  Chip,
} from '@mui/material';
import {
  Dashboard,
  People,
  LocalShipping,
  Inventory,
  Receipt,
  AttachMoney,
  Assessment,
  Settings,
  ExpandLess,
  ExpandMore,
  ShoppingCart,
  Storefront,
  AccountBalance,
  BarChart,
  Category,
  Branding,
  Straighten,
  LocalOffer,
  TrendingUp,
  TrendingDown,
  Warning,
  Payment,
  ReceiptLong,
  Print,
  Download,
} from '@mui/icons-material';
import { useAuth } from '../../context/AuthContext';

const drawerWidth = 260;

const menuItems = [
  {
    text: 'Dashboard',
    icon: <Dashboard />,
    path: '/dashboard',
  },
  {
    text: 'Customers',
    icon: <People />,
    path: '/customers',
  },
  {
    text: 'Suppliers',
    icon: <LocalShipping />,
    path: '/suppliers',
  },
  {
    text: 'Items',
    icon: <Inventory />,
    path: '/items',
    subItems: [
      { text: 'All Items', path: '/items' },
      { text: 'Brands', path: '/items/brands' },
      { text: 'Groups', path: '/items/groups' },
      { text: 'Sections', path: '/items/sections' },
      { text: 'Units', path: '/items/units' },
      { text: 'Taxes', path: '/items/taxes' },
    ],
  },
  {
    text: 'Sales',
    icon: <ShoppingCart />,
    path: '/sales/entry',
    subItems: [
      { text: 'Sales Entry', path: '/sales/list' },
      { text: 'Sales Return', path: '/sales/return' },
    ],
  },
  {
    text: 'Purchases',
    icon: <Storefront />,
    path: '/purchases/entry',
    subItems: [
      { text: 'Purchase Order', path: '/purchases/order' },
      { text: 'Purchase Entry', path: '/purchases/entry' },
      { text: 'Purchase Return', path: '/purchases/return' },
      { text: 'GRN Verification', path: '/purchases/grn' },
    ],
  },
  {
    text: 'Accounts',
    icon: <AccountBalance />,
    path: '/accounts/receipts',
    subItems: [
      { text: 'Bill Receipts', path: '/accounts/receipts' },
      { text: 'Bill Payments', path: '/accounts/payments' },
      { text: 'Ledger', path: '/accounts/ledger' },
    ],
  },
  {
    text: 'Reports',
    icon: <BarChart />,
    path: '/reports/sales',
    subItems: [
      { text: 'Sales Report', path: '/reports/sales' },
      { text: 'Sales Details', path: '/reports/sales-details' },
      { text: 'Purchase Report', path: '/reports/purchases' },
      { text: 'Purchase Details', path: '/reports/purchase-details' },
      { text: 'Customer Receipts', path: '/reports/customer-receipts' },
      { text: 'Supplier Payments', path: '/reports/supplier-payments' },
      { text: 'Stock Report', path: '/reports/stock' },
    ],
  },
  {
    text: 'Settings',
    icon: <Settings />,
    path: '/settings',
  },
];

const Sidebar = ({ mobileOpen, handleDrawerToggle }) => {
  const navigate = useNavigate();
  const location = useLocation();
  const { user } = useAuth();
  const [openSubMenus, setOpenSubMenus] = useState({});

  const handleSubMenuToggle = (text) => {
    setOpenSubMenus((prev) => ({
      ...prev,
      [text]: !prev[text],
    }));
  };

  const isActive = (path) => {
    return location.pathname === path || location.pathname.startsWith(path + '/');
  };

  const isSubItemActive = (subItems) => {
    return subItems?.some(sub => location.pathname === sub.path);
  };

  const drawer = (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* Header */}
      <Toolbar sx={{ 
        backgroundColor: '#1976d2',
        minHeight: 64,
        px: 2,
      }}>
        <Typography variant="h6" sx={{ color: 'white', fontWeight: 700 }}>
          📦 Inventory Pro
        </Typography>
      </Toolbar>

      {/* User Info */}
      <Box sx={{ p: 2, bgcolor: '#f5f7fa', borderBottom: '1px solid #e0e0e0' }}>
        <Box display="flex" alignItems="center" gap={2}>
          <Avatar sx={{ bgcolor: '#1976d2' }}>
            {user?.fullName?.charAt(0) || 'U'}
          </Avatar>
          <Box>
            <Typography variant="body2" fontWeight={600}>
              {user?.fullName || 'User'}
            </Typography>
            <Chip
              label={user?.role || 'USER'}
              size="small"
              color="primary"
              sx={{ height: 20, fontSize: '0.625rem' }}
            />
          </Box>
        </Box>
      </Box>

      {/* Menu */}
      <Box sx={{ flexGrow: 1, overflow: 'auto' }}>
        <List sx={{ pt: 1 }}>
          {menuItems.map((item) => (
            <React.Fragment key={item.text}>
              <ListItem
                button
                onClick={() => {
                  if (item.subItems) {
                    handleSubMenuToggle(item.text);
                  } else {
                    navigate(item.path);
                    if (mobileOpen) handleDrawerToggle();
                  }
                }}
                sx={{
                  mx: 1,
                  borderRadius: 2,
                  mb: 0.5,
                  backgroundColor: isActive(item.path) || isSubItemActive(item.subItems) 
                    ? '#1976d2' 
                    : 'transparent',
                  color: isActive(item.path) || isSubItemActive(item.subItems) 
                    ? 'white' 
                    : 'inherit',
                  '&:hover': {
                    backgroundColor: isActive(item.path) || isSubItemActive(item.subItems)
                      ? '#1565c0'
                      : '#e3f2fd',
                  },
                }}
              >
                <ListItemIcon
                  sx={{
                    color: isActive(item.path) || isSubItemActive(item.subItems)
                      ? 'white'
                      : '#1976d2',
                    minWidth: 40,
                  }}
                >
                  {item.icon}
                </ListItemIcon>
                <ListItemText 
                  primary={item.text} 
                  primaryTypographyProps={{
                    fontWeight: isActive(item.path) || isSubItemActive(item.subItems) 
                      ? 600 
                      : 400,
                  }}
                />
                {item.subItems &&
                  (openSubMenus[item.text] ? <ExpandLess /> : <ExpandMore />)}
              </ListItem>
              {item.subItems && (
                <Collapse in={openSubMenus[item.text]} timeout="auto" unmountOnExit>
                  <List component="div" disablePadding>
                    {item.subItems.map((subItem) => (
                      <ListItem
                        button
                        key={subItem.text}
                        onClick={() => {
                          navigate(subItem.path);
                          if (mobileOpen) handleDrawerToggle();
                        }}
                        sx={{
                          pl: 4,
                          mx: 1,
                          borderRadius: 2,
                          mb: 0.5,
                          backgroundColor: isActive(subItem.path) 
                            ? '#e3f2fd' 
                            : 'transparent',
                          '&:hover': {
                            backgroundColor: '#f5f7fa',
                          },
                        }}
                      >
                        <ListItemText
                          primary={subItem.text}
                          primaryTypographyProps={{
                            fontSize: '0.875rem',
                            fontWeight: isActive(subItem.path) ? 500 : 400,
                            color: isActive(subItem.path) ? '#1976d2' : 'inherit',
                          }}
                        />
                        {isActive(subItem.path) && (
                          <Box sx={{ width: 4, height: 4, borderRadius: '50%', bgcolor: '#1976d2' }} />
                        )}
                      </ListItem>
                    ))}
                  </List>
                </Collapse>
              )}
            </React.Fragment>
          ))}
        </List>
      </Box>

      {/* Footer */}
      <Box sx={{ p: 2, borderTop: '1px solid #e0e0e0', bgcolor: '#f8f9fa' }}>
        <Typography variant="caption" color="textSecondary" display="block" align="center">
          Inventory Pro v1.0.0
        </Typography>
        <Typography variant="caption" color="textSecondary" display="block" align="center">
          © {new Date().getFullYear()} All rights reserved
        </Typography>
      </Box>
    </Box>
  );

  return (
    <Box
      component="nav"
      sx={{ width: { md: drawerWidth }, flexShrink: { md: 0 } }}
    >
      {/* Mobile Drawer */}
      <Drawer
        variant="temporary"
        open={mobileOpen}
        onClose={handleDrawerToggle}
        ModalProps={{ keepMounted: true }}
        sx={{
          display: { xs: 'block', md: 'none' },
          '& .MuiDrawer-paper': {
            boxSizing: 'border-box',
            width: drawerWidth,
          },
        }}
      >
        {drawer}
      </Drawer>

      {/* Desktop Drawer */}
      <Drawer
        variant="permanent"
        sx={{
          display: { xs: 'none', md: 'block' },
          '& .MuiDrawer-paper': {
            boxSizing: 'border-box',
            width: drawerWidth,
            borderRight: '1px solid #e0e0e0',
            backgroundColor: '#ffffff',
          },
        }}
        open
      >
        {drawer}
      </Drawer>
    </Box>
  );
};

export default Sidebar;
